using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed metadata retrieval: GetTypeInfo<T>()
//    Returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"  Kind: {personInfo.Kind}");
Console.WriteLine($"  Properties: {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");

// 2) Probe without throwing: TryGetTypeInfo(Type, out JsonTypeInfo?)
//    Returns false instead of throwing when metadata isn't available.

// Case A — type IS resolvable
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
{
    var typed = (JsonTypeInfo<Person>)found!;
    Console.WriteLine($"\nTryGetTypeInfo(Person) succeeded — Kind: {typed.Kind}");
}

// Case B — type is NOT resolvable (use a resolver that only handles Person)
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new PersonOnlyResolver()
};

if (restrictedOptions.TryGetTypeInfo(typeof(Order), out _))
{
    Console.WriteLine("\nTryGetTypeInfo(Order) succeeded (unexpected)");
}
else
{
    Console.WriteLine("\nTryGetTypeInfo(Order) returned false — no metadata, no exception.");
}

// --- Types used in the demo ---

record Person(string Name, int Age);
record Order(int Id, decimal Total);

// A custom resolver that only provides metadata for Person
sealed class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) =>
        type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}
